#include <iostream>

struct Rectangle
{
    int width;
    int height;
};

Rectangle scale(const Rectangle& rect, int factor)
{
    return Rectangle{ rect.width * factor, rect.height * factor };
}

int main()
{
    int w, h, factor;
    std::cin >> w >> h >> factor;

    Rectangle original{ w, h };
    Rectangle scaled = scale(original, factor);

    std::cout << scaled.width << " x " << scaled.height << '\n';

    return 0;
}

